/*
 * Secure Firmware Update with Signature Verification (ESP-IDF)
 * Implements A/B partition updates with fallback and secure boot
 */

#include "esp_ota_ops.h"
#include "esp_secure_boot.h"
#include "esp_efuse.h"
#include "esp_log.h"
#include "mbedtls/sha256.h"
#include "mbedtls/rsa.h"

static const char *TAG = "SECURE_OTA";

// RSA public key for signature verification (2048-bit)
static const uint8_t RSA_PUBLIC_KEY[] = {
    0x30, 0x82, 0x01, 0x22, 0x30, 0x0d, 0x06, 0x09,
    // ... RSA public key DER format ...
};

typedef struct {
    uint32_t magic;           // 0x53455346 ("SESF")
    uint32_t version;
    uint32_t image_size;
    uint8_t sha256_hash[32];
    uint8_t signature[256];   // RSA-2048 signature
    uint32_t timestamp;
    uint32_t min_version;     // Anti-rollback protection
} firmware_header_t;

/**
 * Verify firmware signature using RSA-PSS
 */
esp_err_t verify_firmware_signature(
    const uint8_t *firmware_data,
    size_t firmware_size,
    const firmware_header_t *header)
{
    esp_err_t ret = ESP_FAIL;
    mbedtls_rsa_context rsa;
    mbedtls_sha256_context sha_ctx;
    uint8_t hash[32];

    // Initialize RSA context
    mbedtls_rsa_init(&rsa, MBEDTLS_RSA_PKCS_V21, MBEDTLS_MD_SHA256);

    // Parse public key
    size_t key_len = sizeof(RSA_PUBLIC_KEY);
    if (mbedtls_rsa_parse_public_key(&rsa, RSA_PUBLIC_KEY, key_len) != 0) {
        ESP_LOGE(TAG, "Failed to parse RSA public key");
        goto cleanup;
    }

    // Calculate SHA-256 hash of firmware image
    mbedtls_sha256_init(&sha_ctx);
    mbedtls_sha256_starts(&sha_ctx, 0);
    mbedtls_sha256_update(&sha_ctx, firmware_data, firmware_size);
    mbedtls_sha256_finish(&sha_ctx, hash);
    mbedtls_sha256_free(&sha_ctx);

    // Verify hash matches header
    if (memcmp(hash, header->sha256_hash, 32) != 0) {
        ESP_LOGE(TAG, "Firmware hash mismatch");
        goto cleanup;
    }

    // Verify RSA signature
    int result = mbedtls_rsa_rsassa_pss_verify(
        &rsa,
        NULL, NULL,
        MBEDTLS_RSA_PUBLIC,
        MBEDTLS_MD_SHA256,
        32,
        hash,
        header->signature
    );

    if (result != 0) {
        ESP_LOGE(TAG, "Invalid firmware signature: %d", result);
        goto cleanup;
    }

    ESP_LOGI(TAG, "Firmware signature verified successfully");
    ret = ESP_OK;

cleanup:
    mbedtls_rsa_free(&rsa);
    return ret;
}

/**
 * Anti-rollback protection: verify firmware version
 */
esp_err_t verify_firmware_version(const firmware_header_t *header)
{
    uint32_t current_version;

    // Read minimum version from eFuse (one-time programmable)
    esp_efuse_read_field_blob(ESP_EFUSE_SECURE_VERSION, &current_version, 32);

    if (header->min_version < current_version) {
        ESP_LOGE(TAG, "Firmware rollback detected: %u < %u",
                 header->min_version, current_version);
        return ESP_ERR_INVALID_VERSION;
    }

    ESP_LOGI(TAG, "Firmware version check passed: %u >= %u",
             header->min_version, current_version);
    return ESP_OK;
}

/**
 * Perform secure OTA update with A/B partition fallback
 */
esp_err_t perform_secure_ota_update(
    const uint8_t *firmware_data,
    size_t firmware_size)
{
    esp_err_t err;
    esp_ota_handle_t ota_handle = 0;
    const esp_partition_t *update_partition = NULL;
    const esp_partition_t *configured_partition = NULL;
    const esp_partition_t *running_partition = NULL;

    // Parse firmware header
    if (firmware_size < sizeof(firmware_header_t)) {
        ESP_LOGE(TAG, "Firmware too small");
        return ESP_ERR_INVALID_SIZE;
    }

    const firmware_header_t *header = (const firmware_header_t *)firmware_data;

    // Verify magic number
    if (header->magic != 0x53455346) {
        ESP_LOGE(TAG, "Invalid firmware magic");
        return ESP_ERR_INVALID_ARG;
    }

    // Verify signature
    err = verify_firmware_signature(
        firmware_data + sizeof(firmware_header_t),
        header->image_size,
        header
    );
    if (err != ESP_OK) {
        return err;
    }

    // Anti-rollback protection
    err = verify_firmware_version(header);
    if (err != ESP_OK) {
        return err;
    }

    // Get partition information
    running_partition = esp_ota_get_running_partition();
    update_partition = esp_ota_get_next_update_partition(NULL);

    ESP_LOGI(TAG, "Running partition: %s", running_partition->label);
    ESP_LOGI(TAG, "Update partition: %s", update_partition->label);

    // Begin OTA update
    err = esp_ota_begin(update_partition, OTA_SIZE_UNKNOWN, &ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "OTA begin failed: %s", esp_err_to_name(err));
        return err;
    }

    // Write firmware to update partition
    err = esp_ota_write(
        ota_handle,
        firmware_data + sizeof(firmware_header_t),
        header->image_size
    );
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "OTA write failed: %s", esp_err_to_name(err));
        esp_ota_abort(ota_handle);
        return err;
    }

    // Finalize OTA update
    err = esp_ota_end(ota_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "OTA end failed: %s", esp_err_to_name(err));
        return err;
    }

    // Set boot partition to newly updated partition
    err = esp_ota_set_boot_partition(update_partition);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Set boot partition failed: %s", esp_err_to_name(err));
        return err;
    }

    ESP_LOGI(TAG, "OTA update successful. Rebooting...");
    esp_restart();

    return ESP_OK;
}

/**
 * Application main: enable secure boot and configure OTA
 */
void app_main(void)
{
    // Verify secure boot is enabled
    if (!esp_secure_boot_enabled()) {
        ESP_LOGE(TAG, "Secure boot is NOT enabled!");
        ESP_LOGE(TAG, "Enable secure boot in menuconfig:");
        ESP_LOGE(TAG, "Security features -> Enable secure boot in bootloader");
    } else {
        ESP_LOGI(TAG, "Secure boot enabled");
    }

    // Display current firmware version
    const esp_app_desc_t *app_desc = esp_ota_get_app_description();
    ESP_LOGI(TAG, "Firmware version: %s", app_desc->version);
    ESP_LOGI(TAG, "IDF version: %s", app_desc->idf_ver);

    // OTA update logic would be triggered here
    // Example: HTTP download, MQTT message, or USB update
}

/*
 * Disable UART/JTAG Debug Interfaces in Production
 * Uses eFuse bits to permanently disable debug access
 */

#include "esp_efuse.h"
#include "esp_log.h"
#include "driver/uart.h"

static const char *TAG = "PROD_SECURITY";

/**
 * Disable JTAG debugging permanently using eFuse
 * WARNING: This is irreversible once eFuse is burned!
 */
esp_err_t disable_jtag_permanently(void)
{
    esp_err_t err;

    // Check if JTAG is already disabled
    bool jtag_disabled = esp_efuse_read_field_bit(ESP_EFUSE_DIS_USB_JTAG);

    if (jtag_disabled) {
        ESP_LOGI(TAG, "JTAG already disabled");
        return ESP_OK;
    }

    ESP_LOGW(TAG, "Disabling JTAG permanently via eFuse");
    ESP_LOGW(TAG, "This operation is IRREVERSIBLE!");

    // Burn eFuse to disable JTAG (ESP32-C3/S3)
    err = esp_efuse_write_field_bit(ESP_EFUSE_DIS_USB_JTAG);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to disable JTAG: %s", esp_err_to_name(err));
        return err;
    }

    // Also disable direct boot (forces secure boot)
    err = esp_efuse_write_field_bit(ESP_EFUSE_DIS_DIRECT_BOOT);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to disable direct boot: %s", esp_err_to_name(err));
        return err;
    }

    ESP_LOGI(TAG, "JTAG and direct boot disabled successfully");
    return ESP_OK;
}

/**
 * Configure UART with authentication for production
 * Disable boot messages and require authentication
 */
esp_err_t configure_secure_uart(void)
{
    uart_config_t uart_config = {
        .baud_rate = 115200,
        .data_bits = UART_DATA_8_BITS,
        .parity = UART_PARITY_DISABLE,
        .stop_bits = UART_STOP_BITS_1,
        .flow_ctrl = UART_HW_FLOWCTRL_DISABLE,
    };

    // Install UART driver
    esp_err_t err = uart_driver_install(
        UART_NUM_0,
        1024, // RX buffer
        0,    // No TX buffer (disable output)
        0,
        NULL,
        0
    );

    if (err != ESP_OK) {
        ESP_LOGE(TAG, "UART driver install failed: %s", esp_err_to_name(err));
        return err;
    }

    err = uart_param_config(UART_NUM_0, &uart_config);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "UART config failed: %s", esp_err_to_name(err));
        return err;
    }

    // Disable bootloader UART output
    esp_efuse_write_field_bit(ESP_EFUSE_DISABLE_DL_DECRYPT);
    esp_efuse_write_field_bit(ESP_EFUSE_DISABLE_DL_ENCRYPT);
    esp_efuse_write_field_bit(ESP_EFUSE_DISABLE_DL_CACHE);

    ESP_LOGI(TAG, "Secure UART configuration complete");
    ESP_LOGI(TAG, "Bootloader UART output disabled");

    return ESP_OK;
}

/**
 * Production security initialization
 */
void initialize_production_security(void)
{
#ifdef CONFIG_PRODUCTION_BUILD
    ESP_LOGI(TAG, "Initializing production security features");

    // Disable JTAG permanently
    disable_jtag_permanently();

    // Configure secure UART
    configure_secure_uart();

    // Disable ROM download mode
    esp_efuse_write_field_bit(ESP_EFUSE_DIS_DOWNLOAD_MODE);

    // Enable flash encryption
    if (!esp_flash_encryption_enabled()) {
        ESP_LOGW(TAG, "Flash encryption not enabled!");
    }

    ESP_LOGI(TAG, "Production security features initialized");
#else
    ESP_LOGW(TAG, "Development build - debug interfaces enabled");
#endif
}

/*
 * Privilege Separation for IoT Services
 * Drop root privileges and implement least privilege principle
 */

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/capability.h>
#include <pwd.h>
#include <grp.h>
#include <errno.h>
#include <string.h>
#include <sys/prctl.h>

#define SERVICE_USER "iotservice"
#define SERVICE_GROUP "iotservice"

/**
 * Drop root privileges and run as unprivileged user
 */
int drop_privileges(void)
{
    struct passwd *pw;
    struct group *gr;

    if (geteuid() != 0) {
        fprintf(stderr, "Not running as root, privileges already dropped\n");
        return 0;
    }

    // Get service user information
    pw = getpwnam(SERVICE_USER);
    if (pw == NULL) {
        fprintf(stderr, "User %s not found\n", SERVICE_USER);
        return -1;
    }

    gr = getgrnam(SERVICE_GROUP);
    if (gr == NULL) {
        fprintf(stderr, "Group %s not found\n", SERVICE_GROUP);
        return -1;
    }

    // Change to service user's home directory
    if (chdir(pw->pw_dir) != 0) {
        fprintf(stderr, "Failed to chdir to %s: %s\n", pw->pw_dir, strerror(errno));
        return -1;
    }

    // Clear supplementary groups
    if (setgroups(0, NULL) != 0) {
        fprintf(stderr, "Failed to clear supplementary groups: %s\n", strerror(errno));
        return -1;
    }

    // Set GID
    if (setgid(gr->gr_gid) != 0) {
        fprintf(stderr, "Failed to setgid(%d): %s\n", gr->gr_gid, strerror(errno));
        return -1;
    }

    // Set UID (irreversible)
    if (setuid(pw->pw_uid) != 0) {
        fprintf(stderr, "Failed to setuid(%d): %s\n", pw->pw_uid, strerror(errno));
        return -1;
    }

    // Verify we cannot escalate back to root
    if (setuid(0) == 0) {
        fprintf(stderr, "ERROR: Was able to escalate back to root!\n");
        return -1;
    }

    printf("Successfully dropped privileges to %s:%s (uid=%d, gid=%d)\n",
           SERVICE_USER, SERVICE_GROUP, pw->pw_uid, gr->gr_gid);

    return 0;
}

/**
 * Set specific Linux capabilities instead of full root
 * Example: Keep CAP_NET_BIND_SERVICE to bind to port 80/443
 */
int set_minimal_capabilities(void)
{
    cap_t caps;
    cap_value_t cap_list[] = {
        CAP_NET_BIND_SERVICE,  // Bind to privileged ports (<1024)
        // CAP_NET_RAW,        // Raw sockets (if needed for ICMP)
    };

    // Get current capabilities
    caps = cap_get_proc();
    if (caps == NULL) {
        fprintf(stderr, "Failed to get capabilities: %s\n", strerror(errno));
        return -1;
    }

    // Clear all capabilities
    if (cap_clear(caps) != 0) {
        fprintf(stderr, "Failed to clear capabilities: %s\n", strerror(errno));
        cap_free(caps);
        return -1;
    }

    // Set specific capabilities
    if (cap_set_flag(caps, CAP_EFFECTIVE, 1, cap_list, CAP_SET) != 0 ||
        cap_set_flag(caps, CAP_PERMITTED, 1, cap_list, CAP_SET) != 0) {
        fprintf(stderr, "Failed to set capability flags: %s\n", strerror(errno));
        cap_free(caps);
        return -1;
    }

    // Apply capabilities
    if (cap_set_proc(caps) != 0) {
        fprintf(stderr, "Failed to apply capabilities: %s\n", strerror(errno));
        cap_free(caps);
        return -1;
    }

    cap_free(caps);
    printf("Successfully set minimal capabilities\n");

    return 0;
}

/**
 * Enable additional security features
 */
int enable_security_features(void)
{
    // Disable core dumps (prevent memory disclosure)
    if (prctl(PR_SET_DUMPABLE, 0) != 0) {
        fprintf(stderr, "Failed to disable core dumps: %s\n", strerror(errno));
        return -1;
    }

    // Prevent privilege escalation via setuid
    if (prctl(PR_SET_NO_NEW_PRIVS, 1, 0, 0, 0) != 0) {
        fprintf(stderr, "Failed to set no_new_privs: %s\n", strerror(errno));
        return -1;
    }

    // Set process name for monitoring
    prctl(PR_SET_NAME, "iot-service", 0, 0, 0);

    printf("Security features enabled: core dumps disabled, no_new_privs set\n");

    return 0;
}

/**
 * Initialize service with privilege separation
 */
int main(int argc, char **argv)
{
    printf("IoT Service starting (PID: %d)...\n", getpid());

    // Perform privileged initialization (e.g., open ports, load config)
    printf("Running privileged initialization...\n");

    // Set minimal capabilities before dropping privileges
    if (set_minimal_capabilities() != 0) {
        fprintf(stderr, "Failed to set capabilities\n");
        return 1;
    }

    // Drop root privileges
    if (drop_privileges() != 0) {
        fprintf(stderr, "Failed to drop privileges\n");
        return 1;
    }

    // Enable additional security features
    if (enable_security_features() != 0) {
        fprintf(stderr, "Failed to enable security features\n");
        return 1;
    }

    // Run main service loop with unprivileged user
    printf("Service running as UID %d, GID %d\n", getuid(), getgid());
    printf("Entering main service loop...\n");

    // Main application logic here...
    while (1) {
        sleep(60);
    }

    return 0;
}
